
"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Instagram, Zap, Lock, ShoppingBag, Trash2, LogOut, X, CreditCard, Wallet } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { ServiceCard, MakeupService } from '@/components/ServiceCard';
import { AIGeneratorDialog } from '@/components/AIGeneratorDialog';
import { cn } from "@/lib/utils";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
  SheetFooter,
} from "@/components/ui/sheet";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";

const categories = [
  { id: "all", name: "الكل - All" },
  { id: "face", name: "الوجه - Face" },
  { id: "eyes", name: "العيون - Eyes" },
  { id: "lips", name: "الشفاه - Lips" },
  { id: "cheeks", name: "الخدود والإضاءة - Cheeks" },
  { id: "tools", name: "الأدوات - Tools" }
];

export default function GirlsStore() {
  const { toast } = useToast();
  const [isSupervisor, setIsSupervisor] = useState(false);
  const [clickCount, setClickCount] = useState(0);
  const [selectedCategoryId, setSelectedCategoryId] = useState("all");
  
  // Cart States
  const [cart, setCart] = useState<{ service: MakeupService, quantity: number }[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'cash' | 'whish'>('cash');

  // Admin Security States
  const [isPasswordDialogOpen, setIsPasswordDialogOpen] = useState(false);
  const [passwordInput, setPasswordInput] = useState("");

  const [services, setServices] = useState<(MakeupService & { categoryId?: string })[]>(() => [
    { 
      id: '1', 
      name: "Signature Gloss", 
      price: 45, 
      description: "High Shine & Deep Hydration for a flawless glow.", 
      imageUrl: "https://images.unsplash.com/photo-1522335789203-aabd1fc54bc9?q=80&w=600",
      categoryId: "lips"
    },
    { 
      id: '2', 
      name: "Velvet Matte", 
      price: 55, 
      description: "Intense pigment with a weightless comfortable finish.", 
      imageUrl: "https://images.unsplash.com/photo-1512496011212-323a784629c2?q=80&w=600",
      categoryId: "face"
    },
    { 
      id: '3', 
      name: "Glow Palette", 
      price: 65, 
      description: "Highlighter and bronzer for the ultimate summer radiance.", 
      imageUrl: "https://images.unsplash.com/photo-1522338242992-e1a54906a8da?q=80&w=600",
      categoryId: "cheeks"
    }
  ]);

  const handleAdminTrigger = () => {
    if (isSupervisor) return;
    setClickCount(prev => prev + 1);
  };

  useEffect(() => {
    if (clickCount === 7) {
      setIsPasswordDialogOpen(true);
      setClickCount(0);
    }
  }, [clickCount]);

  const handlePasswordSubmit = () => {
    if (passwordInput === "Hassan@GS#7") {
      setIsSupervisor(true);
      setIsPasswordDialogOpen(false);
      setPasswordInput("");
      toast({
        title: "ACCESS GRANTED",
        description: "Hassan Deeb Studio controls active.",
      });
    } else {
      toast({
        variant: "destructive",
        title: "ACCESS DENIED",
        description: "Incorrect password.",
      });
      setPasswordInput("");
    }
  };

  const handleLogout = () => {
    setIsSupervisor(false);
    toast({
      title: "LOGGED OUT",
      description: "Admin session closed.",
    });
  };

  const addToCart = (service: MakeupService) => {
    setCart(prev => {
      const existing = prev.find(item => item.service.id === service.id);
      if (existing) {
        return prev.map(item => 
          item.service.id === service.id 
          ? { ...item, quantity: item.quantity + 1 } 
          : item
        );
      }
      return [...prev, { service, quantity: 1 }];
    });
    toast({
      title: "Added to Cart",
      description: `${service.name} has been added to your bag.`,
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.service.id !== id));
  };

  const cartTotal = useMemo(() => {
    return cart.reduce((total, item) => total + (item.service.price * item.quantity), 0);
  }, [cart]);

  const sendOrderWhatsApp = () => {
    const phoneNumber = "96176511272";
    const paymentStr = paymentMethod === 'whish' 
      ? "Whish Money (+96176511272)" 
      : "Cash on Delivery (دليفري كاش)";

    let message = `*طلب جديد من Girls Store*\n\n`;
    cart.forEach(item => {
      message += `- ${item.service.name} (x${item.quantity}) = $${item.service.price * item.quantity}\n`;
    });
    message += `\n*المجموع الكلي: $${cartTotal}*\n`;
    message += `\n*طريقة الدفع:* ${paymentStr}\n`;
    message += `\n_Hassan Deeb Studio_`;
    
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const addService = (name: string, description: string) => {
    const newService: MakeupService & { categoryId?: string } = {
      id: Date.now().toString(),
      name,
      price: 45,
      description,
      imageUrl: `https://picsum.photos/seed/${Date.now()}/800/800`,
      categoryId: selectedCategoryId === "all" ? "face" : selectedCategoryId
    };
    setServices([newService, ...services]);
  };

  const updateService = (updated: MakeupService) => {
    setServices(services.map(s => s.id === updated.id ? { ...updated, categoryId: (s as any).categoryId } : s));
  };

  const deleteService = (id: string) => {
    setServices(services.filter(s => s.id !== id));
  };

  const filteredServices = useMemo(() => {
    if (selectedCategoryId === "all") return services;
    return services.filter(s => s.categoryId === selectedCategoryId);
  }, [services, selectedCategoryId]);

  return (
    <div className="min-h-screen flex flex-col pb-20">
      {/* Header */}
      <header className="pt-12 pb-6 px-6 text-center">
        <p className="text-[10px] tracking-[0.4em] text-pink-500/80 font-bold uppercase mb-4">
          POWERED BY HASSAN DEEB
        </p>
        <h1 
          onClick={handleAdminTrigger}
          className="font-display text-5xl md:text-7xl font-black uppercase leading-none tracking-tighter cursor-pointer select-none mb-6 text-pink-600 drop-shadow-sm transition-transform active:scale-95"
        >
          girls<br />store<span className="text-pink-400">.</span>
        </h1>

        {/* Categories Navigation */}
        <div className="flex overflow-x-auto pb-4 no-scrollbar gap-2 px-4 justify-start md:justify-center mt-4">
          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setSelectedCategoryId(cat.id)}
              className={cn(
                "whitespace-nowrap px-6 py-2 rounded-full text-[10px] uppercase tracking-widest font-black transition-all border",
                selectedCategoryId === cat.id 
                  ? "bg-pink-500 text-white border-pink-500 shadow-lg scale-105" 
                  : "bg-white/50 text-pink-400 border-pink-100 hover:bg-white"
              )}
            >
              {cat.name}
            </button>
          ))}
        </div>
      </header>

      {/* Main Feed */}
      <main className="flex-grow max-w-2xl mx-auto px-6 py-8 w-full space-y-8">
        {isSupervisor && (
          <div className="glass p-8 rounded-[3rem] mb-12 flex flex-col items-center gap-6 border-pink-200 animate-in fade-in zoom-in duration-500 relative">
            <Button 
              onClick={handleLogout}
              variant="ghost" 
              className="absolute top-4 right-4 text-pink-400 hover:text-pink-600"
              size="sm"
            >
              <LogOut className="w-4 h-4 mr-2" /> Exit
            </Button>
            
            <div className="text-center">
              <h3 className="font-display text-xl uppercase font-black italic text-pink-700">Supervisor Active</h3>
              <p className="text-pink-500 text-[10px] uppercase tracking-widest mt-1">Manage store assets.</p>
            </div>
            <div className="flex gap-4">
              <AIGeneratorDialog onGenerated={addService} />
              <Button 
                onClick={() => addService("New Product", "Describe the product details...")}
                variant="outline"
                className="rounded-full bg-white/60 border-pink-200 text-[10px] uppercase tracking-widest h-12 px-8 text-pink-700 hover:bg-white"
              >
                <Plus className="w-4 h-4 mr-2" /> Manual Add
              </Button>
            </div>
          </div>
        )}

        <div className="space-y-8">
          {filteredServices.length > 0 ? (
            filteredServices.map(service => (
              <ServiceCard 
                key={service.id} 
                service={service} 
                isSupervisor={isSupervisor}
                onUpdate={updateService}
                onDelete={deleteService}
                onAddToCart={() => addToCart(service)}
              />
            ))
          ) : (
            <div className="text-center py-20 glass rounded-[3rem]">
              <p className="text-pink-400 uppercase tracking-widest text-xs">No items in this category yet.</p>
            </div>
          )}

          {isSupervisor && (
            <div 
              onClick={() => addService("New Collection", "Details coming soon...")}
              className="aspect-square border-4 border-dashed border-pink-300 rounded-[3rem] flex flex-col items-center justify-center text-pink-400 hover:bg-white/50 transition-all cursor-pointer group"
            >
              <Plus size={48} strokeWidth={1} className="group-hover:scale-125 transition-transform" />
              <span className="text-[10px] uppercase tracking-[0.4em] mt-4 font-black">Add Collection</span>
            </div>
          )}
        </div>
      </main>

      {/* Floating Cart Button */}
      {!isSupervisor && (
        <Sheet open={isCartOpen} onOpenChange={setIsCartOpen}>
          <SheetTrigger asChild>
            <Button className="fixed bottom-8 right-8 h-16 w-16 rounded-full bg-pink-500 text-white shadow-2xl hover:bg-pink-600 transition-all hover:scale-110 z-50">
              <div className="relative">
                <ShoppingBag className="w-7 h-7" />
                {cart.length > 0 && (
                  <span className="absolute -top-2 -right-2 bg-white text-pink-500 text-[10px] font-black h-5 w-5 rounded-full flex items-center justify-center border-2 border-pink-500">
                    {cart.reduce((a, b) => a + b.quantity, 0)}
                  </span>
                )}
              </div>
            </Button>
          </SheetTrigger>
          <SheetContent className="glass border-pink-200 sm:max-w-md overflow-y-auto no-scrollbar">
            <SheetHeader>
              <SheetTitle className="font-display text-2xl uppercase font-black text-pink-600">Your Bag</SheetTitle>
              <SheetDescription className="text-pink-400 uppercase text-[10px] tracking-widest">
                Review your items and choose payment method.
              </SheetDescription>
            </SheetHeader>
            
            <ScrollArea className="h-auto mt-8 pr-4 mb-6">
              {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-center py-20">
                  <ShoppingBag className="w-12 h-12 text-pink-100 mb-4" />
                  <p className="text-pink-300 uppercase text-[10px] tracking-widest">Your bag is empty.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  {cart.map((item) => (
                    <div key={item.service.id} className="flex gap-4 items-center bg-white/40 p-4 rounded-3xl border border-pink-100">
                      <div className="w-16 h-16 rounded-2xl overflow-hidden relative border border-pink-100">
                        <img src={item.service.imageUrl} className="object-cover w-full h-full" alt={item.service.name} />
                      </div>
                      <div className="flex-grow">
                        <h4 className="font-bold text-pink-900 text-sm leading-tight">{item.service.name}</h4>
                        <p className="text-pink-500 font-black text-xs mt-1">
                          {item.quantity} x ${item.service.price}
                        </p>
                      </div>
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        onClick={() => removeFromCart(item.service.id)}
                        className="text-pink-200 hover:text-pink-500"
                      >
                        <X className="w-4 h-4" />
                      </Button>
                    </div>
                  ))}
                </div>
              )}
            </ScrollArea>

            {cart.length > 0 && (
              <div className="space-y-6 pb-20">
                {/* Payment Method Selector */}
                <div className="p-6 bg-white/60 rounded-[2rem] border border-pink-100 space-y-4 shadow-sm">
                  <Label className="text-pink-600 font-black uppercase text-[10px] tracking-[0.2em] flex items-center gap-2">
                    <Wallet className="w-3 h-3" /> Select Payment Method
                  </Label>
                  <RadioGroup 
                    defaultValue="cash" 
                    onValueChange={(v) => setPaymentMethod(v as any)} 
                    className="grid gap-3"
                  >
                    <div className={cn(
                      "flex items-center space-x-3 p-4 rounded-2xl transition-all border",
                      paymentMethod === 'cash' ? "bg-pink-50 border-pink-200" : "bg-transparent border-transparent"
                    )}>
                      <RadioGroupItem value="cash" id="cash" className="border-pink-300 text-pink-500" />
                      <Label htmlFor="cash" className="text-pink-700 text-xs font-bold cursor-pointer flex-grow">
                        Cash on Delivery (دليفري كاش)
                      </Label>
                    </div>
                    <div className={cn(
                      "flex items-center space-x-3 p-4 rounded-2xl transition-all border",
                      paymentMethod === 'whish' ? "bg-pink-50 border-pink-200" : "bg-transparent border-transparent"
                    )}>
                      <RadioGroupItem value="whish" id="whish" className="border-pink-300 text-pink-500" />
                      <Label htmlFor="whish" className="text-pink-700 text-xs font-bold cursor-pointer flex-grow">
                        Whish Money (+96176511272)
                      </Label>
                    </div>
                  </RadioGroup>
                </div>

                <div className="w-full space-y-4">
                  <div className="flex justify-between items-center px-2">
                    <span className="text-pink-400 uppercase text-[10px] tracking-widest font-black">Total Amount</span>
                    <span className="text-pink-600 font-display text-2xl font-black">${cartTotal}</span>
                  </div>
                  <Button 
                    onClick={sendOrderWhatsApp}
                    className="w-full h-16 rounded-2xl bg-pink-500 hover:bg-pink-600 text-white font-black uppercase tracking-widest shadow-xl transition-all"
                  >
                    Send to WhatsApp
                  </Button>
                </div>
              </div>
            )}
          </SheetContent>
        </Sheet>
      )}

      {/* Footer */}
      <footer className="py-20 text-center">
        <p className="text-[11px] font-bold tracking-[0.2em] uppercase mb-8 text-pink-600">
          WHISH MONEY / OMT / CASH ON DELIVERY
        </p>
        
        <div className="flex justify-center gap-12 mb-12 text-pink-400">
          <Instagram size={28} className="hover:scale-110 hover:text-pink-600 transition-all cursor-pointer" />
          <Zap size={28} />
        </div>
        
        <p className="text-[9px] opacity-60 uppercase tracking-[0.5em] font-bold text-pink-900">
          © 2026 GIRLS STORE • BY HASSAN DEEB
        </p>
      </footer>

      {/* Password Dialog */}
      <Dialog open={isPasswordDialogOpen} onOpenChange={setIsPasswordDialogOpen}>
        <DialogContent className="sm:max-w-[400px] glass border-pink-200">
          <DialogHeader>
            <DialogTitle className="font-display text-xl uppercase text-pink-700">Studio Access</DialogTitle>
            <DialogDescription className="text-pink-500/70 uppercase text-[10px] tracking-widest">
              Please enter the supervisor password to manage store assets.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="password" title="Password" />
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-pink-300" />
                <Input
                  id="password"
                  type="password"
                  placeholder="••••••••"
                  className="pl-10 h-12 bg-white/60 border-pink-100 rounded-2xl"
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handlePasswordSubmit()}
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button 
              onClick={handlePasswordSubmit}
              className="w-full h-12 rounded-2xl bg-pink-500 hover:bg-pink-600 text-white font-black uppercase tracking-widest text-[10px]"
            >
              Verify Access
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
