
"use client";

import React, { useState } from 'react';
import Image from 'next/image';
import { ShoppingCart, Edit2, Trash2, Check, Plus } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";

export interface MakeupService {
  id: string;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
}

interface ServiceCardProps {
  service: MakeupService;
  isSupervisor: boolean;
  onUpdate: (service: MakeupService) => void;
  onDelete: (id: string) => void;
  onAddToCart?: () => void;
}

export function ServiceCard({ service, isSupervisor, onUpdate, onDelete, onAddToCart }: ServiceCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedService, setEditedService] = useState(service);

  const handleSave = () => {
    onUpdate(editedService);
    setIsEditing(false);
  };

  return (
    <div className="glass rounded-[3rem] overflow-hidden group">
      {/* Product Image */}
      <div className="aspect-square relative overflow-hidden bg-white/20">
        <Image
          src={service.imageUrl}
          alt={service.name}
          fill
          className="object-cover transition-transform duration-700 group-hover:scale-110"
        />
        {/* Price Badge */}
        <div className="absolute top-6 right-6 bg-white text-pink-500 px-6 py-2 rounded-full font-display font-black text-xl shadow-lg">
          ${service.price}
        </div>
      </div>

      {/* Content */}
      <div className="p-8 text-left">
        {isEditing ? (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4">
            <Input 
              className="bg-white/60 border-pink-100 text-pink-900 font-display text-2xl h-14 rounded-2xl"
              value={editedService.name} 
              onChange={(e) => setEditedService({...editedService, name: e.target.value})} 
            />
            <div className="flex gap-2 items-center bg-white/40 p-2 rounded-2xl px-4">
              <span className="text-pink-400 font-black">$</span>
              <Input 
                className="bg-transparent border-none text-pink-600 font-bold h-10 p-0 focus-visible:ring-0"
                type="number"
                value={editedService.price} 
                onChange={(e) => setEditedService({...editedService, price: Number(e.target.value)})} 
              />
            </div>
            <Textarea 
              className="bg-white/60 border-pink-100 text-pink-800 rounded-2xl min-h-[100px]"
              value={editedService.description} 
              onChange={(e) => setEditedService({...editedService, description: e.target.value})} 
            />
            <div className="flex gap-3">
              <Button onClick={handleSave} className="flex-1 bg-pink-500 text-white hover:bg-pink-600 rounded-full h-12 uppercase font-black tracking-widest text-[10px]">
                Save Changes
              </Button>
              <Button onClick={() => setIsEditing(false)} variant="outline" className="rounded-full h-12 border-pink-200 text-pink-400 uppercase font-black tracking-widest text-[10px]">
                Cancel
              </Button>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div>
              <h2 className="text-3xl font-display font-black uppercase text-pink-600 leading-tight">
                {service.name}
              </h2>
              <p className="text-pink-400/80 font-body text-sm mt-2">
                {service.description}
              </p>
            </div>

            <div className="pt-4 border-t border-pink-100">
              {!isSupervisor ? (
                <Button 
                  onClick={onAddToCart}
                  className="w-full bg-white text-pink-500 hover:bg-pink-50 border border-pink-100 rounded-2xl h-16 text-[14px] uppercase tracking-widest font-black transition-all shadow-md group/btn"
                >
                  <Plus className="mr-2 w-5 h-5 group-hover/btn:rotate-90 transition-transform" /> ADD TO BAG
                </Button>
              ) : (
                <div className="flex gap-3">
                  <Button 
                    onClick={() => setIsEditing(true)}
                    className="flex-1 bg-white/60 border border-pink-100 text-pink-500 hover:bg-white rounded-full h-14 text-[10px] uppercase font-bold tracking-widest"
                  >
                    <Edit2 className="w-4 h-4 mr-2" /> Edit
                  </Button>
                  <Button 
                    onClick={() => onDelete(service.id)}
                    variant="destructive"
                    className="rounded-full h-14 w-14 p-0 shadow-lg"
                  >
                    <Trash2 className="w-5 h-5" />
                  </Button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
